<template>
  <div class="item-sales-wrapper container">
    <div v-if="loading" class="loading-overlay">
      <div class="overlay-content"><img src="@/assets/img/loading.gif" style="width: 60px" /></div>
    </div>
    <Header />
    <div class="content-wrapper">
      <div class="filter-toggle-wrapper" ref="toggleFilter">
        <span>
          <button class="filter-toggle" @click="toggleFilter()" :class="isFilterActive ? 'collasped' : ''">Search <fa :icon="['fas', 'angles-down']"></fa></button>
        </span>
        <div class="filter-wrapper" :class="[isFilterActive ? 'slide-in' : 'slide-out']">
          <div class="filter-content-wrapper">
            <div class="filter-header">
              <div class="filter-popup-container">
                <popup class="filter-popup-wrapper">
                  <template #header>
                    <button class="filter-btn">
                      <span><fa :icon="['fas', 'sliders']" /><span id="display-selection">Daily</span></span
                      ><fa icon="angle-down" />
                    </button>
                  </template>
                  <template #content>
                    <div class="display-selection-wrapper">
                      <span>
                        <input type="radio" name="display_type" value="D" v-model="displayType" @change="selectedDisplayType" id="display-daily" />
                        <fa class="checkmark" icon="check" />
                        <label for="display-daily">Daily</label>
                      </span>
                      <span>
                        <input type="radio" name="display_type" value="W" v-model="displayType" @change="selectedDisplayType" id="display-weekly" />
                        <fa class="checkmark" icon="check" />
                        <label for="display-weekly">Weekly</label>
                      </span>
                      <span>
                        <input type="radio" name="display_type" value="M" v-model="displayType" @change="selectedDisplayType" id="display-monthly" />
                        <fa class="checkmark" icon="check" />
                        <label for="display-monthly">Monthly</label>
                      </span>
                    </div>
                  </template>
                </popup>
                <popup class="filter-popup-wrapper">
                  <template #header>
                    <button class="filter-btn">
                      <span><fa :icon="['far', 'file-lines']" /><span id="num-selection">Item #</span></span
                      ><fa icon="angle-down" />
                    </button>
                  </template>
                  <template #content>
                    <div class="num-selection-wrapper">
                      <span>
                        <input type="radio" name="show_item" value="Y" v-model="showItem" @change="selectedShowNum" id="item-num" checked="checked" />
                        <fa class="checkmark" icon="check" />
                        <label for="item-num">Item #</label>
                      </span>
                      <span>
                        <input type="radio" name="show_item" value="N" v-model="showItem" @change="selectedShowNum" id="upc" />
                        <fa class="checkmark" icon="check" />
                        <label for="upc">UPC</label>
                      </span>
                    </div>
                  </template>
                </popup>
              </div>
              <button class="search-btn btn btn-square" @click="searchWithFilter"><fa icon="magnifying-glass"></fa></button>
            </div>
            <div class="calendar-wrapper">
              <VueDatePicker
                class="start-date"
                v-model="startDate"
                auto-apply
                :enable-time-picker="false"
                month-name-format="long"
                week-start="0"
                :day-names="['S', 'M', 'T', 'W', 'T', 'F', 'S']"
                format="MMM. dd, yyyy"
                placeholder="From"
              >
                <template #clear-icon></template>
              </VueDatePicker>

              <span v-if="startDate" class="start-btns">
                <button @click="deductStartDate(startDate)"><fa icon="angle-left" /></button>
                <button @click="addStartDate(startDate)"><fa icon="angle-right" /></button>
              </span>

              <VueDatePicker
                class="end-date"
                v-model="endDate"
                auto-apply
                :enable-time-picker="false"
                month-name-format="long"
                week-start="0"
                :day-names="['S', 'M', 'T', 'W', 'T', 'F', 'S']"
                format="MMM. dd, yyyy"
                placeholder="To"
              >
                <template #input-icon></template>
                <template #clear-icon></template>
              </VueDatePicker>

              <span v-if="endDate" class="end-btns">
                <button @click="deductEndDate(endDate)"><fa icon="angle-left" /></button>
                <button @click="addEndDate(endDate)"><fa icon="angle-right" /></button>
              </span>
            </div>
            <label class="filter-label">Search By</label>
            <div>
              <div class="type-select">
                <popup class="filter-popup-wrapper">
                  <template #header>
                    <button class="filter-btn">
                      <span><fa :icon="['fas', 'filter']" /><span id="filter-selection">UPC</span></span><fa icon="angle-down" />
                    </button>
                  </template>
                  <template #content>
                    <div class="num-selection-wrapper">
                      <span>
                        <input type="radio" name="select_filter" value="item-num" v-model="selectedType" @change="selectedFilterType" id="item-num" checked="checked" />
                        <fa class="checkmark" icon="check" />
                        <label for="item-num">Item #</label>
                      </span>
                      <span>
                        <input type="radio" name="select_filter" value="upc" v-model="selectedType" @change="selectedFilterType" id="upc" />
                        <fa class="checkmark" icon="check" />
                        <label for="upc">UPC</label>
                      </span>
                      <span>
                        <input type="radio" name="select_filter" value="dept-category" v-model="selectedType" @change="selectedFilterType" id="dept-cat" />
                        <fa class="checkmark" icon="check" />
                        <label for="dept-cat">Group of Items</label>
                      </span>
                      <span>
                        <input type="radio" name="select_filter" value="special" v-model="selectedType" @change="selectedFilterType" id="special" />
                        <fa class="checkmark" icon="check" />
                        <label for="special">Special</label>
                      </span>
                    </div>
                  </template>
                </popup>
                <p class="filter-desc" v-if="selectedType == 'item-num'">Enter multiple Item # delimited by ' , '</p>
              </div>
              <Transition name="fade">
                <div class="filter-option" v-if="selectedType == 'item-num'">
                  <textarea v-model="itemNum"></textarea>
                </div>
              </Transition>
              <Transition name="fade">
                <div class="filter-option text-input" v-if="selectedType == 'upc'">
                  <input v-if="selectedType == 'upc'" @keyup.enter="searchWithFilter" type="text" v-model="upc" />
                </div>
              </Transition>
              <Transition name="fade">
                <div class="filter-option" v-if="selectedType == 'dept-category'">
                  <label>
                    <span>Type</span>
                    <select v-model="selectedAmtType">
                      <option v-for="amtType in amtTypes" :key="amtType.qty_type" :value="amtType.qty_type">{{ amtType.qty_dsc }}</option>
                    </select>
                  </label>
                  <label>
                    <span>Category</span>
                    <select v-model="selectedCategory">
                      <option value="">--</option>
                      <option v-for="category in categories" :key="category.cat_no" :value="category.cat_pathkey">{{ category.cat_display }}</option>
                    </select>
                  </label>
                  <label>
                    <span>Department</span>
                    <select v-model="selectedDept">
                      <option value="">--</option>
                      <option v-for="dept in depts" :key="dept.dep_no" :value="dept.dep_no">{{ dept.dep_display }}</option>
                    </select>
                  </label>
                </div>
              </Transition>
              <Transition name="fade">
                <div class="filter-option" v-if="selectedType == 'special'">
                  <select v-model="selectedOption">
                    <option value="">--</option>
                    <option v-for="special in specials" :key="special.id" :value="special.id">{{ special.display }}</option>
                  </select>
                  <select v-if="selectedOption == '1'" v-model="specialOption">
                    <option v-for="origin in origins" :key="origin.id" :value="origin.id">{{ origin.display }}</option>
                  </select>
                  <select v-else-if="selectedOption == '2'" v-model="specialOption">
                    <option v-for="brand in brands" :key="brand.id" :value="brand.id">{{ brand.display }}</option>
                  </select>
                  <select v-else-if="selectedOption == '3'" v-model="specialOption">
                    <option v-for="employee in employees" :key="employee.id" :value="employee.id">{{ employee.display }}</option>
                  </select>
                  <select v-else-if="selectedOption == '4'" v-model="specialOption">
                    <option v-for="vendor in vendors" :key="vendor.id" :value="vendor.id">{{ vendor.display }}</option>
                  </select>
                </div>
              </Transition>
            </div>
          </div>
        </div>
      </div>
      <div class="content">
        <div v-if="!empty && itemSalesData.total_amount <= 0 || !empty && !itemSalesData.total_amount" class="no-results"><fa :icon="['fas', 'magnifying-glass']" />No search results found</div>
        <div v-if="!empty && itemSalesData.total_amount > 0" class="item-sales-list-wrapper">
          <ul :class="itemSelected.item_no ? 'none' : ''" class="item-sale-list">
            <h5>Item Sales List</h5>
            <li v-for="itemSale in itemSales" :key="itemSale" @click="getItem(itemSale)" :class="{ highlight: itemSale.upc == itemSelected.upc }">
              <p v-if="showItemNum">{{ itemSale.item_no }}</p>
              <p v-else-if="!showItemNum">{{ itemSale.upc }}</p>
              <p>{{ itemSale.itemname }}</p>
              <p>{{ itemSale.itemdesc }} {{ itemSale.itemnetwt }}</p>
            </li>
          </ul>

        <div :class="itemSelected.item_no ? 'mobile' : ''">
          <span><button class="close-btn" @click="backItemList()"><fa icon="close" /></button></span>
          <DataTable
            v-if="itemSelected.item_no"
            id="rpt-table"
            class="tb-wrapper"
            :value="itemSelected.details"
            rowGroupMode="subheader"
            groupRowsBy="upc"
            scrollable
            scrollHeight="760px"
            :virtualScrollerOptions="{ itemSize: 46 }"
            :exportFilename="fileName"
            ref="dt"
          >
            <template #header>
              <div class="table-header-wrapper">
                <div class="table-header">
                  <h3>{{ this.$route.name }} - {{ storeName }}</h3>
                  <p>As of date {{ formatDate(rptStartDate) }} - {{ formatDate(rptEndDate) }}</p>
                </div>
                <div class="table-btn-group">
                  <button class="print-btn btn btn-circle" onclick="window.print()"><fa icon="print"></fa></button>
                  <button class="excel-btn btn btn-circle" @click="exportCSV($event)"><fa icon="file-excel"></fa></button>
                </div>
              </div>
            </template>
            <template #groupheader>
              <div class="item">
                <span v-if="showItemNum">{{ itemSelected.item_no }}</span>
                <span v-else-if="!showItemNum">{{ itemSelected.upc }}</span> - {{ itemSelected.itemname }} {{ itemSelected.itemdesc }} {{ itemSelected.itemnetwt }}
              </div>
            </template>
            <Column field="period" header="Date"></Column>
            <Column class="amount" field="qty" header="Quantity"></Column>
            <Column class="average" field="average" header="Average ($)"></Column>
            <Column class="amount" field="amount" header="Amount ($)"></Column>
            <Column field="" header="" style="display: none"></Column>

            <ColumnGroup type="footer">
              <Row>
                <Column footer="Total" />
                <Column footer=""><template #footer>{{ itemSelected.subtotal_qty }}</template></Column>
                <Column footer=""><template #footer>{{ itemAvg }}</template></Column>
                <Column footer=""><template #footer>{{ itemSelected.subtotal_amount }}</template></Column>
              </Row>
            </ColumnGroup>
          </DataTable>
        </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
/* eslint-disable */
import Header from "@/components/Header.vue";
import axios from "axios";
import moment from "moment";
import { ref } from "vue";
import Popup from "@/components/Popup.vue";

export default {
  components: {
    Header,
    Popup,
  },
  setup() {
    const date = ref(0);

    return {
      date,
    };
  },
  data() {
    return {
      isFilterActive: false,
      empty: true,
      loading: false,
      storeName: localStorage.getItem("StoreName"),
      itemSalesData: [],
      itemSales: [],
      startDate: "",
      endDate: "",
      rptStartDate: "",
      rptEndDate: "",
      selectedType: "upc",
      displayType: "D",
      offset: 2,
      showItem: "Y",
      itemNum: [],
      upc: "",
      deptCat: [],
      amtTypes: "",
      categories: "",
      depts: "",
      brands: "",
      employees: "",
      origins: "",
      vendors: "",
      specials: [
        { id: 1, display: "Origin" },
        { id: 2, display: "Brand" },
        { id: 3, display: "Handle By" },
        { id: 4, display: "Pr. Vendor" },
      ],
      selectedAmtType: "S",
      selectedCategory: "",
      selectedDept: "",
      selectedOption: 0,
      specialOption: "",
      filterData: "",
      showItemNum: true,
      itemSelected: [],
      itemAvg: ""
    };
  },
  mounted() {
    axios
      .get("https://cloudbackofficereportapidev.azurewebsites.net/AmtType")
      .then((response) => {
        this.amtTypes = response.data.datas;
      })
      .catch((error) => console.log(error.response));

    axios
      .get("https://cloudbackofficereportapidev.azurewebsites.net/Category")
      .then((response) => {
        this.categories = response.data.datas;
      })
      .catch((error) => console.log(error.response));

    axios
      .get("https://cloudbackofficereportapidev.azurewebsites.net/Department")
      .then((response) => {
        this.depts = response.data.datas;
      })
      .catch((error) => console.log(error.response));

    axios
      .get("https://cloudbackofficereportapidev.azurewebsites.net/DropDown/Brand")
      .then((response) => {
        this.brands = response.data.datas;
      })
      .catch((error) => console.log(error.response));

    axios
      .get("https://cloudbackofficereportapidev.azurewebsites.net/DropDown/Employees")
      .then((response) => {
        this.employees = response.data.datas;
      })
      .catch((error) => console.log(error.response));

    axios
      .get("https://cloudbackofficereportapidev.azurewebsites.net/DropDown/Origin")
      .then((response) => {
        this.origins = response.data.datas;
      })
      .catch((error) => console.log(error.response));

    axios
      .get("https://cloudbackofficereportapidev.azurewebsites.net/DropDown/VendorCode")
      .then((response) => {
        this.vendors = response.data.datas;
      })
      .catch((error) => console.log(error.response));
  },
  beforeMount() {
    window.addEventListener('click', this.close);
  },
  unmounted() {
    window.removeEventListener('click', this.close);
  },
  methods: {
    toggleFilter() {
      this.isFilterActive = !this.isFilterActive;
    },
    close(e) {
      if (!this.$refs.toggleFilter.contains(e.target)) {
        this.isFilterActive = false;
      }
    },
    formatPrice(value) {
      if (!value || value == 0) {
        return "0.00";
      }
      let val = (value / 1).toFixed(2).replace(",", ".");
      return val.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
    },
    formatNumber(value) {
      return value.toString().replace(/\B(?=(\d{3})+(?!\d))/g, ",");
    },
    formatDate(date) {
      return moment(date).format("MMM. DD, yyyy");
    },
    addStartDate(date) {
      this.startDate = new Date(date.getTime() + 60 * 60 * 24 * 1000);
    },
    deductStartDate(date) {
      this.startDate = new Date(date.getTime() - 60 * 60 * 24 * 1000);
    },
    addEndDate(date) {
      this.endDate = new Date(date.getTime() + 60 * 60 * 24 * 1000);
    },
    deductEndDate(date) {
      this.endDate = new Date(date.getTime() - 60 * 60 * 24 * 1000);
    },
    exportCSV() {
      this.$refs.dt.exportCSV();
    },
    selectedDisplayType() {
      var value = "Nothing selected",
        selected = document.querySelector('input[name="display_type"]:checked'),
        selection = document.querySelector("#display-selection");

      if (selected) {
        value = document.querySelector('label[for="' + selected.id + '"]').innerHTML;
      }

      selection.innerHTML = value;
    },
    selectedShowNum() {
      var value = "Nothing selected",
        selected = document.querySelector('input[name="show_item"]:checked'),
        selection = document.querySelector("#num-selection");

      if (selected) {
        value = document.querySelector('label[for="' + selected.id + '"]').innerHTML;
      }

      selection.innerHTML = value;
    },
    selectedFilterType() {
      var value = "Nothing selected",
        selected = document.querySelector('input[name="select_filter"]:checked'),
        selection = document.querySelector("#filter-selection");

      if (selected) {
        value = document.querySelector('label[for="' + selected.id + '"]').innerHTML;
      }

      selection.innerHTML = value;
    },
    calculateSalesAvg(values) {
      var total = 0,
        length = values.length;
      for (let value of values) {
        total += value.average;
      }
      return "$" + (total / length).toFixed(2);
    },
    searchWithFilter() {
      this.loading = true;
      this.isFilterActive = false;
      this.itemSelected = "";
      this.itemSales = [];

      if (this.startDate && this.endDate) {
        this.rptStartDate = moment(this.startDate).format("YYYY-MM-DD");
        this.rptEndDate = moment(this.endDate).format("YYYY-MM-DD");
      } else {
        this.rptStartDate = "";
        this.rptEndDate = "";
      }

      if (this.showItem == "Y") {
        this.showItemNum = true;
      } else if (this.showItem == "N") {
        this.showItemNum = false;
      }

      if (this.selectedType == "item-num") {
        if (this.itemNum.indexOf(",") > -1) {
          this.itemNum = this.itemNum.replace(" ", "").split(",");
        }
        this.filterData = {
          itemnos: this.itemNum,
          sDate: this.rptStartDate,
          eDate: this.rptEndDate,
          type: this.displayType,
          offset: this.offset,
          show_upc: this.showItem,
        };
      } else if (this.selectedType == "upc") {
        this.filterData = {
          upc: this.upc,
          sDate: this.rptStartDate,
          eDate: this.rptEndDate,
          type: this.displayType,
          offset: this.offset,
          show_upc: this.showItem,
        };
      } else if (this.selectedType == "dept-category") {
        this.filterData = {
          sDate: this.rptStartDate,
          eDate: this.rptEndDate,
          type: this.displayType,
          offset: this.offset,
          show_upc: this.showItem,
          deptCat: {
            amt_type: this.selectedAmtType,
            cat_pathkey: this.selectedCategory,
            dep_no: "" + this.selectedDept + "",
          },
        };
      } else if (this.selectedType == "special") {
        this.filterData = {
          sDate: this.rptStartDate,
          eDate: this.rptEndDate,
          type: this.displayType,
          offset: this.offset,
          show_upc: this.showItem,
          sp_type: this.selectedOption,
          sp_value: this.specialOption,
        };
      }

      axios
        .post("https://cloudbackofficereportapidev.azurewebsites.net/Report/ItemSales", this.filterData)
        .then((response) => {
          this.itemSalesData = response.data.datas
          this.itemSales = response.data.datas.itemSalesRptItems;
        })
        .catch((error) => console.log(error.response))
        .finally(() => {
          this.loading = false;
          this.empty = false;
        });

        this.startDate = "";
        this.endDate = "";
        this.itemNum = "";
        this.upc = "";
        this.displayType = "D";
        this.showItem = "Y";
        this.selectedAmtType = "S";
        this.selectedCategory = "";
        this.selectedDept = "";
        this.selectedOption = "";
        this.specialOption = 0;
    },
    getItem(value) {
      this.itemSelected = value;
      this.itemAvg = this.itemSelected.details[0].average;
    },
    backItemList() {
      this.itemSelected = "";
    },
  },
  computed: {
    fileName() {
      let excelName = this.$route.name + " " + this.startDate + "-" + this.endDate;
      return excelName;
    },
  },
};
</script>
